47	/* ── Tiny helpers ─────────────────────────────────────────── */
48	
49	function CopyInlineButton({ value, label }: { value: string; label?: string }) {
50	  const [copied, setCopied] = useState(false);
51	  const copy = async () => {
52	    await navigator.clipboard.writeText(value);
53	    setCopied(true);
54	    setTimeout(() => setCopied(false), 1500);
55	  };
56	  const btn = (
57	    <Button variant="ghost" size="icon" className="h-6 w-6 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" onClick={copy}>
58	      {copied ? <Check className="h-3 w-3 text-[hsl(var(--success))]" /> : <Copy className="h-3 w-3" />}
59	    </Button>
60	  );
61	  if (!label) return btn;
62	  return (
63	    <Tooltip>
64	      <TooltipTrigger asChild>{btn}</TooltipTrigger>
65	      <TooltipContent side="top">{copied ? "Copied!" : `Copy ${label}`}</TooltipContent>
66	    </Tooltip>
67	  );
68	}
69	
70	function CopyPathRow({ label, value }: { label: string; value: string }) {
71	  const [copied, setCopied] = useState(false);
72	  const copy = async () => {
73	    await navigator.clipboard.writeText(value);
74	    setCopied(true);
75	    setTimeout(() => setCopied(false), 1500);
76	  };
77	  return (
78	    <div className="group flex items-start gap-2">
79	      <div className="flex-1 min-w-0">
80	        <span className="text-[10px] uppercase text-muted-foreground tracking-wider">{label}</span>
81	        <p className="text-xs font-mono break-all text-foreground/80 mt-0.5">{value}</p>
82	      </div>
83	      <Button variant="ghost" size="icon" className="h-6 w-6 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" onClick={copy}>
84	        {copied ? <Check className="h-3 w-3 text-[hsl(var(--success))]" /> : <Copy className="h-3 w-3" />}
85	      </Button>
86	    </div>
87	  );
88	}
89	
90	function MetaRow({ label, value }: { label: string; value: React.ReactNode }) {
91	  if (!value || value === "—") return null;
92	  return (
93	    <div className="flex items-baseline gap-3">
94	      <span className="text-xs text-muted-foreground shrink-0 w-20">{label}</span>
95	      <span className="text-xs text-foreground overflow-x-auto whitespace-nowrap scrollbar-thin">{value ?? "—"}</span>
96	    </div>
97	  );
98	}
