100	function formatSize(bytes: number | null): string {
101	  if (!bytes) return "—";
102	  if (bytes < 1024) return `${bytes} B`;
103	  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`;
104	  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
105	}
106	
107	function formatDateValue(value: string | null | undefined): string | null {
108	  if (!value) return null;
109	  const d = new Date(value);
110	  if (Number.isNaN(d.getTime())) return null;
111	  return format(d, "MMM d, yyyy");
112	}
