114	/** Full-screen lightbox for viewing images */
115	function Lightbox({ url, alt, onClose }: { url: string; alt: string; onClose: () => void }) {
116	  useEffect(() => {
117	    const handler = (e: KeyboardEvent) => { if (e.key === "Escape") onClose(); };
118	    window.addEventListener("keydown", handler);
119	    return () => window.removeEventListener("keydown", handler);
120	  }, [onClose]);
121	
122	  return (
123	    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80" onClick={onClose}>
124	      <img src={url} alt={alt} className="max-w-[90vw] max-h-[90vh] object-contain" onClick={(e) => e.stopPropagation()} />
125	    </div>
126	  );
127	}
