129	/* ── Find Alternative Images component ────────────────────── */
130	
131	interface SiblingImage {
132	  filename: string;
133	  relative_path: string;
134	  file_size: number;
135	  thumbnail_url?: string;
136	}
137	
138	function FindAlternativeImages({ group, onIngested }: { group: StyleGroup; onIngested?: () => void }) {
139	  const { call } = useAdminApi();
140	  const [loading, setLoading] = useState(false);
141	  const [siblings, setSiblings] = useState<SiblingImage[] | null>(null);
142	  const [error, setError] = useState<string | null>(null);
143	  const [polling, setPolling] = useState(false);
144	  const [requestId, setRequestId] = useState<string | null>(null);
145	  const [initialLoaded, setInitialLoaded] = useState(false);
146	  const [selected, setSelected] = useState<Set<string>>(new Set());
147	  const [ingesting, setIngesting] = useState(false);
148	  const pollTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);
149	  const pollCountRef = useRef(0);
150	
151	  // Cleanup polling on unmount
152	  useEffect(() => {
153	    return () => {
154	      if (pollTimerRef.current) clearInterval(pollTimerRef.current);
155	    };
156	  }, []);
157	
158	  const stopPolling = () => {
159	    if (pollTimerRef.current) {
160	      clearInterval(pollTimerRef.current);
161	      pollTimerRef.current = null;
162	    }
163	    setPolling(false);
164	    pollCountRef.current = 0;
165	  };
166	
167	  const startPolling = (reqId: string) => {
168	    if (pollTimerRef.current) clearInterval(pollTimerRef.current);
169	    pollCountRef.current = 0;
170	    setPolling(true);
171	    setRequestId(reqId);
172	
173	    pollTimerRef.current = setInterval(async () => {
174	      pollCountRef.current++;
175	      if (pollCountRef.current > 30) {
176	        stopPolling();
177	        setError("Scan timed out — the Bridge Agent may be offline. Try again later.");
178	        return;
179	      }
180	
181	      try {
182	        const result = await call("get-sibling-scan-result", { request_id: reqId });
183	        if (result?.status === "completed") {
184	          stopPolling();
185	          const images = (result.images ?? []) as SiblingImage[];
186	          setSiblings(images);
187	          setSelected(new Set());
188	          if (images.length === 0) {
189	            toast("No alternative images found", { description: "No JPG, PNG, or eligible PDF files exist in this folder on the NAS." });
190	          } else {
191	            toast(`Found ${images.length} image${images.length !== 1 ? "s" : ""}`);
192	          }
193	        } else if (result?.status === "failed") {
194	          stopPolling();
195	          const msg = result.error_message || "Scan failed";
196	          setError(msg);
197	          toast.error("Folder scan failed", { description: msg });
198	        }
199	      } catch (e) {
200	        console.warn("Poll error:", (e as Error).message);
201	      }
202	    }, 5000);
203	  };
204	
205	  // Auto-load existing results on mount
206	  useEffect(() => {
207	    if (initialLoaded || !group.folder_path) return;
208	    setInitialLoaded(true);
209	
210	    (async () => {
211	      try {
212	        const result = await call("get-sibling-scan-by-folder", { folder_path: group.folder_path });
213	        if (!result?.found) return;
214	
215	        if (result.status === "completed") {
216	          const images = (result.images ?? []) as SiblingImage[];
217	          setSiblings(images);
218	        } else if (result.status === "failed") {
219	          setError(result.error_message || "Previous scan failed");
220	        } else if (result.status === "pending") {
221	          startPolling(result.request_id as string);
222	        }
223	      } catch {
224	        // Non-fatal
225	      }
226	    })();
227	  }, [group.folder_path]); // eslint-disable-line react-hooks/exhaustive-deps
228	
229	  const handleFind = async () => {
230	    setLoading(true);
231	    setError(null);
232	    setSiblings(null);
233	    setSelected(new Set());
234	    stopPolling();
235	    try {
236	      const result = await call("list-sibling-images", {
237	        folder_path: group.folder_path,
238	        style_group_id: group.id,
239	      });
240	      if (result?.status === "completed") {
241	        const images = (result.images ?? []) as SiblingImage[];
242	        setSiblings(images);
243	        if (images.length === 0) {
244	          toast("No alternative images found", { description: "No JPG, PNG, or eligible PDF files exist in this folder on the NAS." });
245	        }
246	      } else if (result?.status === "failed") {
247	        setError(result.error_message || "Scan failed");
248	      } else if (result?.status === "pending") {
249	        toast("Scan requested", { description: "The Bridge Agent will scan this folder shortly. Waiting for results…" });
250	        startPolling(result.request_id as string);
251	      }
252	    } catch (e) {
253	      const msg = (e as Error).message;
254	      setError(msg);
255	      toast.error("Failed to scan folder", { description: msg });
256	    } finally {
257	      setLoading(false);
258	    }
259	  };
260	
261	  const toggleSelect = (path: string) => {
262	    setSelected(prev => {
263	      const next = new Set(prev);
264	      if (next.has(path)) next.delete(path);
265	      else next.add(path);
266	      return next;
267	    });
268	  };
269	
270	  const toggleAll = () => {
271	    if (!siblings) return;
272	    if (selected.size === siblings.length) {
273	      setSelected(new Set());
274	    } else {
275	      setSelected(new Set(siblings.map(s => s.relative_path)));
276	    }
277	  };
278	
279	  const handleIngest = async () => {
280	    if (!siblings || selected.size === 0) return;
281	    setIngesting(true);
282	    try {
283	      const selectedImages = siblings.filter(s => selected.has(s.relative_path));
284	      const result = await call("ingest-sibling-images", {
285	        style_group_id: group.id,
286	        images: selectedImages,
287	      });
288	      const summary = result?.summary as { created: number; linked: number; errors: number } | undefined;
289	      if (summary) {
290	        const parts: string[] = [];
291	        if (summary.created > 0) parts.push(`${summary.created} added`);
292	        if (summary.linked > 0) parts.push(`${summary.linked} linked`);
293	        if (summary.errors > 0) parts.push(`${summary.errors} failed`);
294	        toast("Images ingested", { description: parts.join(", ") });
295	      } else {
296	        toast("Images ingested");
297	      }
298	      // Remove ingested images from the list
299	      setSiblings(prev => prev?.filter(s => !selected.has(s.relative_path)) ?? null);
300	      setSelected(new Set());
301	      onIngested?.();
302	    } catch (e) {
303	      toast.error("Ingestion failed", { description: (e as Error).message });
304	    } finally {
305	      setIngesting(false);
306	    }
307	  };
308	
309	  return (
310	    <section className="space-y-2.5">
311	      <h4 className="flex items-center gap-1.5 text-xs font-medium uppercase tracking-wider text-muted-foreground">
312	        <FolderSearch className="h-3.5 w-3.5" /> Alternative Images
313	      </h4>
314	      <p className="text-[10px] text-muted-foreground leading-relaxed">
315	        If this group lacks a proper product image, scan the NAS folder for sibling JPG, PNG, or eligible PDF files that could be used instead.
316	      </p>
317	      <Button
318	        variant="outline"
319	        size="sm"
320	        className="gap-1.5 text-xs h-7"
321	        onClick={handleFind}
322	        disabled={loading || polling}
323	        title={loading ? "Scanning folder…" : polling ? "Waiting for agent response…" : undefined}
324	      >
325	        {loading || polling ? <Loader2 className="h-3 w-3 animate-spin" /> : <FolderSearch className="h-3 w-3" />}
326	        {loading ? "Scanning…" : polling ? "Waiting for results…" : siblings ? "Re-scan Folder" : "Find Sibling Files"}
327	      </Button>
328	
329	      {error && (
330	        <p className="text-[10px] text-destructive">{error}</p>
331	      )}
332	
333	      {siblings && siblings.length > 0 && (
334	        <div className="space-y-2 rounded-md border border-border p-2 bg-muted/20">
335	          <div className="flex items-center justify-between">
336	            <p className="text-[10px] text-muted-foreground font-medium">
337	              Found {siblings.length} image{siblings.length !== 1 ? "s" : ""}:
338	            </p>
339	            <div className="flex items-center gap-2">
340	              <Button variant="ghost" size="sm" className="h-5 text-[10px] px-1.5" onClick={toggleAll}>
341	                {selected.size === siblings.length ? "Deselect All" : "Select All"}
342	              </Button>
343	            </div>
344	          </div>
345	          <div className="grid grid-cols-2 gap-2">
346	            {siblings.map((img) => {
347	              const isSelected = selected.has(img.relative_path);
348	              return (
349	                <div
350	                  key={img.relative_path}
351	                  className={cn(
352	                    "rounded-md border overflow-hidden bg-background cursor-pointer transition-colors",
353	                    isSelected ? "border-primary ring-1 ring-primary/30" : "border-border/50 hover:border-border"
354	                  )}
355	                  onClick={() => toggleSelect(img.relative_path)}
356	                >
357	                  {img.thumbnail_url ? (
358	                    <div className="aspect-square w-full bg-muted/30 overflow-hidden relative">
359	                      <img
360	                        src={img.thumbnail_url}
361	                        alt={img.filename}
362	                        className="h-full w-full object-contain"
363	                        loading="lazy"
364	                      />
365	                      {isSelected && (
366	                        <div className="absolute top-1 right-1 h-5 w-5 rounded-full bg-primary flex items-center justify-center">
367	                          <Check className="h-3 w-3 text-primary-foreground" />
368	                        </div>
369	                      )}
370	                    </div>
371	                  ) : (
372	                    <div className="aspect-square w-full bg-muted/30 flex items-center justify-center relative">
373	                      <ImageOff className="h-6 w-6 text-muted-foreground/20" />
374	                      {isSelected && (
375	                        <div className="absolute top-1 right-1 h-5 w-5 rounded-full bg-primary flex items-center justify-center">
376	                          <Check className="h-3 w-3 text-primary-foreground" />
377	                        </div>
378	                      )}
379	                    </div>
380	                  )}
381	                  <div className="p-1.5 space-y-0.5">
382	                    <p className="font-mono text-[10px] truncate" title={img.relative_path}>
383	                      {img.filename}
384	                    </p>
385	                    <p className="text-[9px] text-muted-foreground">
386	                      {img.file_size ? `${(img.file_size / 1024).toFixed(0)} KB` : ""}
387	                    </p>
388	                  </div>
389	                </div>
390	              );
391	            })}
392	          </div>
393	          {selected.size > 0 && (
394	            <Button
395	              size="sm"
396	              className="w-full gap-1.5 text-xs h-7"
397	              onClick={handleIngest}
398	              disabled={ingesting}
399	              title={ingesting ? "Adding images to group, please wait…" : undefined}
400	            >
401	              {ingesting ? <Loader2 className="h-3 w-3 animate-spin" /> : <Check className="h-3 w-3" />}
402	              Add {selected.size} Image{selected.size !== 1 ? "s" : ""} to Group
403	            </Button>
404	          )}
405	        </div>
406	      )}
407	
408	      {polling && (
409	        <div className="rounded-md border border-[hsl(var(--warning)/0.3)] bg-[hsl(var(--warning)/0.05)] p-2.5 space-y-1">
410	          <p className="text-[10px] text-[hsl(var(--warning))] font-medium flex items-center gap-1">
411	            <Loader2 className="h-3 w-3 animate-spin" /> Waiting for Bridge Agent…
412	          </p>
413	          <p className="text-[10px] text-muted-foreground leading-relaxed">
414	            The Bridge Agent is scanning folder <span className="font-mono">{group.folder_path}</span> for sibling JPG, PNG, and eligible PDF files. This typically takes 10–30 seconds.
415	          </p>
416	        </div>
417	      )}
418	
419	      {siblings && siblings.length === 0 && !polling && (
420	        <p className="text-[10px] text-muted-foreground/60">No sibling files found in this folder.</p>
421	      )}
422	    </section>
423	  );
424	}
