426	/* ── Main component ───────────────────────────────────────── */
427	
428	export default function StyleGroupDetailPanel({ group, onClose }: StyleGroupDetailPanelProps) {
429	  const queryClient = useQueryClient();
430	  const { call: adminApi } = useAdminApi();
431	  const [localPrimaryId, setLocalPrimaryId] = useState<string | null>(group.primary_asset_id);
432	
433	  // Keep localPrimaryId in sync when the group prop changes (e.g. after rebuild/refetch)
434	  useEffect(() => {
435	    setLocalPrimaryId(group.primary_asset_id);
436	  }, [group.primary_asset_id]);
437	  const [selectedAssetId, setSelectedAssetId] = useState<string | null>(null);
438	  const [carouselIndex, setCarouselIndex] = useState(0);
439	  const [lightboxUrl, setLightboxUrl] = useState<string | null>(null);
440	  const [tagInput, setTagInput] = useState("");
441	  const [aiTagging, setAiTagging] = useState(false);
442	  const [syncingTags, setSyncingTags] = useState(false);
443	
444	  const ERP_MG_CUTOFF = "2025-05-14";
445	
446	  // Fetch ERP item data for this group's SKU (legacy check + description)
447	  const { data: erpItemData } = useQuery({
448	    queryKey: ["erp-item-data", group.sku],
449	    queryFn: async () => {
450	      const { data } = await supabase
451	        .from("erp_items_current")
452	        .select("erp_updated_at, item_description")
453	        .eq("style_number", group.sku)
454	        .limit(1)
455	        .maybeSingle();
456	      return data ?? null;
457	    },
458	    staleTime: 5 * 60 * 1000,
459	  });
460	
461	  const isLegacyGroup = erpItemData?.erp_updated_at ? erpItemData.erp_updated_at < ERP_MG_CUTOFF : false;
462	  const erpDescription = erpItemData?.item_description ?? null;
463	
464	  // Fetch all assets in this group
465	  const { data: groupAssets, isLoading: assetsLoading } = useQuery({
466	    queryKey: ["style-group-assets", group.id],
467	    queryFn: async () => {
468	      const { data, error } = await supabase
469	        .from("assets")
470	        .select("*")
471	        .eq("style_group_id", group.id)
472	        .eq("is_deleted", false)
473	        .order("filename");
474	      if (error) throw error;
475	      return (data ?? []) as Asset[];
476	    },
477	  });
478	
479	  // NAS config for path display
480	  const { data: nasConfig } = useQuery({
481	    queryKey: ["nas-config"],
482	    queryFn: async () => {
483	      const { data } = await supabase
484	        .from("admin_config")
485	        .select("key, value")
486	        .in("key", ["NAS_HOST", "NAS_IP", "NAS_SHARE"]);
487	      const map: Record<string, string> = {};
488	      for (const row of data ?? []) map[row.key] = typeof row.value === "string" ? row.value : String(row.value);
489	      return {
490	        NAS_HOST: map.NAS_HOST ?? "nas",
491	        NAS_IP: map.NAS_IP ?? "0.0.0.0",
492	        NAS_SHARE: map.NAS_SHARE ?? "share",
493	      } as NasConfig;
494	    },
495	    staleTime: 5 * 60 * 1000,
496	  });
497	
498	  // Style guide source files for licensed groups
499	  const { data: styleGuideSources } = useQuery({
500	    queryKey: ["sku-files-used", group.sku],
501	    enabled: !!group.sku && group.is_licensed,
502	    queryFn: async () => {
503	      const { data } = await supabase
504	        .from("sku_files_used")
505	        .select("id, file_name, style_guide_file_id, style_guide_files(filename, licensor_name, property_folder)")
506	        .eq("sku", group.sku)
507	        .order("file_name");
508	      return (data ?? []) as Array<{
509	        id: string;
510	        file_name: string;
511	        style_guide_file_id: string | null;
512	        style_guide_files: { filename: string; licensor_name: string | null; property_folder: string | null } | null;
513	      }>;
514	    },
515	    staleTime: 2 * 60 * 1000,
516	  });
517	
518	  const { data: productionOrders } = useQuery({
519	    queryKey: ["style-prod-orders", group.sku],
520	    enabled: !!group.sku,
521	    queryFn: async () => {
522	      const { data, error } = await (supabase as any)
523	        .from("prod_order_headers_current")
524	        .select("id, prod_order_number, order_status, customer_name, quantity, due_date, order_date, erp_updated_at")
525	        .eq("style_number", group.sku)
526	        .order("due_date", { ascending: true, nullsFirst: false })
527	        .order("prod_order_number", { ascending: true });
528	      if (error) throw error;
529	      return (data ?? []) as Array<{
530	        id: string;
531	        prod_order_number: string;
532	        order_status: string | null;
533	        customer_name: string | null;
534	        quantity: number | null;
535	        due_date: string | null;
536	        order_date: string | null;
537	        erp_updated_at: string | null;
538	      }>;
539	    },
540	    staleTime: 2 * 60 * 1000,
541	  });
542	
543	  // Thumbnailed assets for the carousel
544	  const thumbStrip = (groupAssets ?? []).filter((a) => !!a.thumbnail_url);
545	
546	  // Keep carouselIndex in bounds
547	  useEffect(() => {
548	    if (thumbStrip.length > 0 && carouselIndex >= thumbStrip.length) {
549	      setCarouselIndex(thumbStrip.length - 1);
550	    }
551	  }, [thumbStrip.length, carouselIndex]);
